sql:
SELECT AVG(assessments_count) AS average_assessments_per_user
FROM (
    SELECT user_id, COUNT(assessment_id) AS assessments_count
    FROM assessments
    GROUP BY user_id
) AS user_assessments;

SELECT AVG(severity_level) AS average_severity_level
FROM safety_questions
WHERE created_by = 1 AND created_at BETWEEN '2023-04-01' AND '2023-04-30';

SELECT COUNT(question_id) AS high_severity_question_count
FROM safety_questions
WHERE severity_level = 'High';

SELECT MAX(assessment_count) AS highest_assessment_count
FROM (
    SELECT user_id, COUNT(assessment_id) AS assessment_count
    FROM assessments
    GROUP BY user_id
) AS UserAssessmentCounts;

SELECT question_id, question_text, severity_level
FROM safety_questions
WHERE severity_level = 'medium';

